from collections import defaultdict, Counter

def group_by_status(orders: list[dict]) -> dict[str, list[dict]]:
    grouped: defaultdict[str, list[dict]] = defaultdict(list)
    for order in orders:
        grouped[order["status"]].append(order)
    return dict(grouped)

def top_words(text: str, n: int = 10) -> list[tuple[str, int]]:
    counts = Counter(text.lower().split())
    return counts.most_common(n)

# List comprehension — result is iterated multiple times
active_ids: list[int] = [u["id"] for u in users if u["active"]]

# Generator expression — consumed once by sum
total = sum(item["price"] * item["qty"] for item in cart)

# Dict comprehension — invert a mapping
id_to_name: dict[int, str] = {u["id"]: u["name"] for u in users}

# For-loop with side effect — comprehension would be wrong here
for user in users:
    if user["active"]:
        send_notification(user["email"])  # Side effect: don't use comprehension
